import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/fundamentals`},{default:a(()=>[...l[2]||=[n(`Fundamentals`,-1)]]),_:1}),l[5]||=n(` › Chapter 3 `,-1)]),l[6]||=i(`<h1>Chapter 3: Modularity</h1><p class="chapter-desc">How to think about breaking systems into cohesive, loosely coupled parts — the metrics, vocabulary, and tools architects use to measure and maintain structural integrity.</p><div class="stats-bar"><span class="stat-badge">6 Cohesion Types</span><span class="stat-badge">2 Coupling Directions</span><span class="stat-badge">3 Core Metrics</span><span class="stat-badge">5 Static Connascence Types</span><span class="stat-badge">5 Dynamic Connascence Types</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<div class="toc"><h2>Table of Contents</h2><ol><li><a href="#s3-1">Modularity vs Granularity</a></li><li><a href="#s3-2">Defining Modularity</a></li><li><a href="#s3-3">Measuring Modularity — Cohesion</a></li><li><a href="#s3-4">Coupling (Afferent &amp; Efferent)</a></li><li><a href="#s3-5">Core Derived Metrics</a></li><li><a href="#s3-6">Connascence</a></li><li><a href="#s3-7">From Modules to Components</a></li><li><a href="#takeaways">Key Takeaways</a></li></ol></div><h2 class="section-title" id="s3-1">Modularity vs Granularity</h2><div class="content-section"><p>These two terms are often used interchangeably, but they mean different things:</p><table class="comparison-table"><thead><tr><th>Concept</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td><strong>Modularity</strong></td><td>Breaking a system into smaller, separate pieces</td><td>Moving from a monolithic layered architecture to microservices</td></tr><tr><td><strong>Granularity</strong></td><td>The <em>size</em> of those pieces — how large or small each part should be</td><td>Whether an Order service should be one service or split into Order and Invoice services</td></tr></tbody></table><div class="info-box warning-box"><p><strong>&quot;Embrace modularity, but beware of granularity.&quot;</strong> — Mark Richards.<br> Granularity causes services to couple to one another, creating antipatterns like <em>Spaghetti Architecture</em>, <em>Distributed Monoliths</em>, and the <em>Big Ball of Distributed Mud</em>. Too-small pieces mean too many inter-service calls.</p></div><div class="info-box analogy-box"><p><strong>Physics analogy:</strong> Complex systems tend toward entropy (disorder). In a physical system, energy must be added to preserve order. The same is true for software — architects must constantly work to maintain structural soundness. Without active effort, codebases degrade.</p></div></div><h2 class="section-title" id="s3-2">Defining Modularity</h2><div class="content-section"><p>In this book: <strong>modularity = a logical grouping of related code</strong>. This could be a package in Java, a namespace in .NET, a folder in Node.js, or any other mechanism for grouping related things. Importantly, this is a <em>logical</em> separation, not necessarily a physical one.</p><p>Physical separation (separate deployable units) is not implied by logical modularity. A monolith can have excellent logical modularity — its components are just deployed together.</p></div><h2 class="section-title" id="s3-3">Measuring Modularity — Cohesion</h2><div class="content-section"><p><strong>Cohesion</strong> = how related the parts of a module are to each other. A highly cohesive module contains everything it needs to function; splitting it further would only create unnecessary coupling between the pieces.</p><div class="info-box note-box"><p><strong>&quot;Attempting to divide a cohesive module would only result in increased coupling and decreased readability.&quot;</strong> — Larry Constantine</p></div><p>Computer scientists defined a cohesion spectrum — <strong>from best (most cohesive) to worst (least cohesive)</strong>:</p><table class="comparison-table"><thead><tr><th>Type</th><th>Description</th><th>Quality</th></tr></thead><tbody><tr><td><strong>Functional</strong></td><td>Every part is related and the module contains everything it needs to function. The ideal.</td><td>Best</td></tr><tr><td><strong>Sequential</strong></td><td>One module&#39;s output becomes another&#39;s input (pipeline)</td><td>Good</td></tr><tr><td><strong>Communicational</strong></td><td>Two modules operate on the same data or produce the same output. Example: one writes a DB record, the other sends an email based on it.</td><td>Good</td></tr><tr><td><strong>Procedural</strong></td><td>Two modules must execute in a specific order</td><td>Moderate</td></tr><tr><td><strong>Temporal</strong></td><td>Modules related by timing — they run at the same time (e.g., startup initialization routines)</td><td>Weak</td></tr><tr><td><strong>Logical</strong></td><td>Data is related logically but not functionally. Example: <code>StringUtils</code> — all string operations, but unrelated to each other.</td><td>Weak</td></tr><tr><td><strong>Coincidental</strong></td><td>Elements are in the same file for no logical reason other than convenience</td><td>Worst</td></tr></tbody></table><h4 class="subsubsection-title">LCOM — Lack of Cohesion in Methods</h4><p>A structural metric from the Chidamber-Kemerer suite. Measures how many methods in a class share the same fields. High LCOM = low cohesion = the class is likely doing too many unrelated things and should be split.</p><p><strong>Use case:</strong> When analyzing a legacy codebase for migration, use LCOM to identify &quot;God classes&quot; — classes that are incidentally large but have no single coherent purpose.</p></div><h2 class="section-title" id="s3-4">Coupling (Afferent &amp; Efferent)</h2><div class="content-section"><p>Coupling measures the dependencies between code artifacts. Two fundamental directions:</p><table class="comparison-table"><thead><tr><th>Type</th><th>Direction</th><th>Mnemonic</th></tr></thead><tbody><tr><td><strong>Afferent coupling (Ca)</strong></td><td>Incoming connections — how many other modules depend on this one</td><td>&quot;A comes before E&quot; — like &quot;arrives before exits&quot;</td></tr><tr><td><strong>Efferent coupling (Ce)</strong></td><td>Outgoing connections — how many modules this one depends on</td><td>&quot;E for Exit&quot; — the module exits to call others</td></tr></tbody></table></div><h2 class="section-title" id="s3-5">Core Derived Metrics (Robert C. Martin)</h2><div class="content-section"><table class="comparison-table"><thead><tr><th>Metric</th><th>Formula</th><th>Meaning</th><th>Problem zones</th></tr></thead><tbody><tr><td><strong>Abstractness (A)</strong></td><td>abstract artifacts / (concrete + abstract artifacts)</td><td>Ratio of abstractions (interfaces, abstract classes) to concrete implementations. 0 = all concrete, 1 = all abstract.</td><td>Too close to 0: brittle, hard to change. Too close to 1: &quot;AbstractSingletonProxyFactoryBean&quot; — impossible to understand.</td></tr><tr><td><strong>Instability (I)</strong></td><td>Ce / (Ce + Ca)</td><td>Volatility of a code unit. A class with many outgoing dependencies breaks when any of those dependencies changes. 0 = stable, 1 = very unstable.</td><td>High instability in core domain components is dangerous.</td></tr><tr><td><strong>Distance from Main Sequence (D)</strong></td><td>|A + I − 1|</td><td>Holistic health metric. The &quot;main sequence&quot; is the ideal relationship between A and I. Classes near it are balanced.</td><td>Zone of Uselessness (too abstract): hard to use. Zone of Pain (too concrete + unstable): brittle and hard to maintain.</td></tr></tbody></table><div class="info-box analogy-box"><p><strong>Zone of Pain analogy:</strong> A core utility class (like a database connection pool) that every module depends on — but is also concrete and has many outgoing dependencies — is like a fragile keystone in an arch. Everything depends on it, yet it can break at any time. That&#39;s the Zone of Pain.</p></div></div><h2 class="section-title" id="s3-6">Connascence</h2><div class="content-section"><p>Introduced by Meilir Page-Jones (1996), connascence is a vocabulary for describing <em>types</em> of coupling more precisely than just &quot;afferent&quot; and &quot;efferent.&quot; Two components are connascent if a change in one would require the other to be modified to preserve system correctness.</p><h3 class="subsection-title">Static Connascence (source-code level)</h3><table class="comparison-table"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Connascence of Name (CoN)</strong></td><td>Components must agree on the name of an entity</td><td>Method names, parameter names. Most common and most acceptable — modern refactoring tools handle this well.</td></tr><tr><td><strong>Connascence of Type (CoT)</strong></td><td>Components must agree on the type of an entity</td><td>Static typing in Java/C#. Also appears in dynamic languages via selective typing (Clojure Spec).</td></tr><tr><td><strong>Connascence of Meaning (CoM)</strong></td><td>Components must agree on the meaning of particular values</td><td>Hardcoded magic numbers: <code>if (status == 1)</code>. If someone changes what 1 means, everything breaks silently.</td></tr><tr><td><strong>Connascence of Position (CoP)</strong></td><td>Components must agree on the order of values</td><td><code>updateSeat(&quot;14D&quot;, &quot;Ford, N&quot;)</code> — swapping arguments is a valid type match but wrong semantically. Named parameters solve this.</td></tr><tr><td><strong>Connascence of Algorithm (CoA)</strong></td><td>Components must agree on a particular algorithm</td><td>Server and client must use the same hashing algorithm for authentication. If either changes, the handshake breaks.</td></tr></tbody></table><h3 class="subsection-title">Dynamic Connascence (runtime level)</h3><table class="comparison-table"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Connascence of Execution (CoE)</strong></td><td>Order of execution between components matters</td><td>Must call <code>email.setRecipient()</code> before <code>email.send()</code>. Wrong order = broken behavior.</td></tr><tr><td><strong>Connascence of Timing (CoTi)</strong></td><td>Timing of execution between components matters</td><td>Race conditions: two threads running simultaneously produce different results depending on which finishes first.</td></tr><tr><td><strong>Connascence of Values (CoV)</strong></td><td>Multiple values depend on each other and must change together</td><td>A rectangle defined by four corner points — changing one invalidates the others. Or: distributed transactions where all databases must update atomically.</td></tr><tr><td><strong>Connascence of Identity (CoI)</strong></td><td>Multiple components must reference the same entity</td><td>Two independent components sharing a distributed queue must reference the same queue instance.</td></tr></tbody></table><h4 class="subsubsection-title">Connascence Properties</h4><table class="comparison-table"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><strong>Strength</strong></td><td>How easy is it to refactor this coupling? Connascence of Name is the weakest (easiest to fix). Connascence of Algorithm is the strongest (hardest to fix). Prefer weaker forms.</td></tr><tr><td><strong>Locality</strong></td><td>How close are the coupled components? Strong connascence within a module is acceptable. Strong connascence across module boundaries is a red flag.</td></tr><tr><td><strong>Degree</strong></td><td>How many components are affected? A change that impacts 2 classes is better than one that impacts 20.</td></tr></tbody></table><div class="info-box key-point-box"><p><strong>Refactoring rule:</strong> Transform strong connascence into weaker forms. Replace Connascence of Value (magic numbers) with Connascence of Name (named constants). Replace Connascence of Position (positional parameters) with named parameters or parameter objects. Each transformation reduces coupling strength.</p></div></div><h2 class="section-title" id="s3-7">From Modules to Components</h2><div class="content-section"><p>Modules are <em>logical</em> groupings of code; components are the <em>physical deployable units</em> — JARs, DLLs, packages, shared libraries, services. The key insight: good modularity is a prerequisite for good component design. When a codebase has high cohesion and low coupling at the module level, it&#39;s far easier to extract those modules into independently deployable components later.</p><p>This is why architects care about modularity even in monolithic applications — a well-modularized monolith can evolve into a microservices architecture much more cleanly than a Big Ball of Mud can.</p></div><div class="takeaways" id="takeaways"><h3>Key Takeaways — Chapter 3</h3><ul><li><strong>Modularity</strong> is about breaking systems apart. <strong>Granularity</strong> is about size. Beware of excessive granularity — too-small pieces create coupling antipatterns.</li><li>Software systems tend toward entropy — architects must actively maintain structural soundness.</li><li><strong>Cohesion</strong> spectrum: Functional (best) → Sequential → Communicational → Procedural → Temporal → Logical → Coincidental (worst). Aim for functional cohesion.</li><li><strong>LCOM</strong> (Lack of Cohesion in Methods) detects classes doing unrelated things. Use it to find refactoring candidates.</li><li><strong>Afferent coupling</strong> = incoming. <strong>Efferent coupling</strong> = outgoing. High efferent coupling = high instability.</li><li>Three derived metrics: <strong>Abstractness</strong>, <strong>Instability</strong>, <strong>Distance from Main Sequence</strong>. Classes far from the main sequence are in the Zone of Uselessness (too abstract) or Zone of Pain (too concrete + unstable).</li><li><strong>Connascence</strong> is a vocabulary for coupling precision. Static forms (CoN, CoT, CoM, CoP, CoA) are source-level; dynamic forms (CoE, CoTi, CoV, CoI) are runtime-level.</li><li>Prefer weaker connascence forms. Minimize connascence across module boundaries. Refactor strong connascence into weaker forms.</li><li>Well-modularized code is easier to migrate, understand, and evolve — whether it&#39;s in a monolith or distributed architecture.</li></ul></div>`,16),e(`div`,p,[r(m,{to:`/sa/fundamentals/ch2`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 2`,-1)]]),_:1}),r(m,{to:`/sa/fundamentals/ch4`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 4 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};